#define MAXSIZE 5
int stack[MAXSIZE];
int top = -1;

// Push operation
void push(int element) {
 if (top >= MAXSIZE - 1) {
 printf("Stack Overflow!\n");
 return;
 }
 stack[++top] = element;
}

// Pop operation
int pop() {
 if (top == -1) {
 printf("Stack Underflow!\n");
 return -1;
 }
 return stack[top--];
}

// Peek operation
int peek() {
 if (top == -1) {
 printf("Stack is empty!\n");
 return -1;
 }
 return stack[top];
}

// Display stack
void display() {
 if (top == -1) {
 printf("Stack is empty!\n");
 return;
 }
 printf("Stack elements: ");
 for (int i = top; i >= 0; i--)
 printf("%d ", stack[i]);
 printf("\n");
}

#define MAXSIZE 5
int queue[MAXSIZE];
int front = -1, rear = -1;

// Check if queue is empty
int isEmpty() {
 return front == -1;
}

// Check if queue is full
int isFull() {
 return (rear + 1) % MAXSIZE == front;
}

// Enqueue operation
void enqueue(int element) {
 if (isFull()) {
 printf("Queue is full!\n");
 return;
 }
 if (front == -1) front = 0;
 rear = (rear + 1) % MAXSIZE;
 queue[rear] = element;
}

// Dequeue operation
int dequeue() {
 if (isEmpty()) {
 printf("Queue is empty!\n");
 return -1;
 }
 int element = queue[front];
 if (front == rear) {
 front = rear = -1; // Reset queue
 } else {
 front = (front + 1) % MAXSIZE;
 }
 return element;
}

#include <string.h>
#define MAX 100

int checkBalance(char expr[]) {
 char stack[MAX];
 int top = -1;

 for (int i = 0; i < strlen(expr); i++) {
 char c = expr[i];

 // If opening bracket, push to stack
 if (c == '(' || c == '[' || c == '{') {
 stack[++top] = c;
 }
 // If closing bracket, check match
 else if (c == ')' || c == ']' || c == '}') {
 if (top == -1) return 0; // Unmatched

 char topChar = stack[top--];
 if ((c == ')' && topChar != '(') ||
 (c == ']' && topChar != '[') ||
 (c == '}' && topChar != '{')) {
 return 0; // Mismatch
 }
 }
 }
 return (top == -1); // Balanced if stack empty
}
